/* eslint-env serviceworker */

import { routes } from './routes.js';
import { assert } from './assertions.js';

routes.set('/request/bot-detection/not-a-bot', async (event) => {
  let req = event.request;
  assert(req.botAnalyzed, false);
  assert(req.botDetected, false);
  assert(req.botName, null);
  assert(req.botCategory, null);
  assert(req.botVerified, null);

  req = new Request('https://www.fastly.com', {
    body: 'I am the body',
    method: 'POST',
  });
  assert(req.botAnalyzed, false);
  assert(req.botDetected, false);
  assert(req.botName, null);
  assert(req.botCategory, null);
  assert(req.botVerified, null);

  return new Response('ok');
});

routes.set('/request/bot-detection/got-a-bot', async (event) => {
  const req = event.request;
  assert(req.botAnalyzed, true);
  assert(req.botDetected, true);
  assert(req.botName, 'BadBot');
  assert(req.botCategory, 'headless');
  assert(req.botVerified, true);
  return new Response('ok');
});

routes.set('/request/bot-detection/verified-false', async (event) => {
  const req = event.request;
  assert(req.botVerified, false);
  return new Response('ok');
});

routes.set('/request/bot-detection/long-bot-name', async (event) => {
  const req = event.request;
  // Force a buffer realloc
  assert(
    req.botName,
    '',
  );
  return new Response('ok');
});
